def solve(input_str):
    lines = input_str.split('\n')
    a = list(map(int, lines[0].split()))
    n = int(lines[1])
    notes = list(map(int, lines[2].split()))
    min_diff = float('inf')
    for i in range(n):
        for j in range(i, n):
            frets = []
            for note in notes:
                possible_frets = []
                for k in range(6):
                    if note - a[k] >= 0:
                        possible_frets.append(note - a[k])
                frets.append(possible_frets)
            min_fret = float('inf')
            max_fret = float('-inf')
            for k in range(n):
                if k < i or k > j:
                    min_fret = min(min_fret, min(frets[k]))
                    max_fret = max(max_fret, max(frets[k]))
            diff = max_fret - min_fret
            min_diff = min(min_diff, diff)
    print(min_diff)
